B.Lf=s(["Gire pesco\xe7o, ombros, quadril, joelhos e tornozelos sem pressa.","Movimentos amplos e suaves, sem for\xe7ar.","Objetivo: soltar as articula\xe7\xf5es e elevar a temperatura do corpo."],t.s)
B.Ig=new A.bl("aquecimento-articular",B.Lf,"Aquecimento articular",B.cb)
B.OL=s(["Deitado de bru\xe7os, bra\xe7os estendidos \xe0 frente.","Eleve bra\xe7os, peito e pernas ao mesmo tempo, contraindo as costas.","Segure 2 segundos no topo e des\xe7a devagar.","Sem for\xe7ar o pesco\xe7o \u2014 olhar para o ch\xe3o."],t.s)
B.Ii=new A.bl("superman",B.OL,"Superman",B.iQ)
B.MI=s(["Deite sob uma mesa firme e segure a borda com as duas m\xe3os.","Corpo reto, calcanhares no ch\xe3o.","Puxe o peito em dire\xe7\xe3o \xe0 mesa, juntando as esc\xe1pulas.","Des\xe7a controlando. Quanto mais horizontal o corpo, mais dif\xedcil."],t.s)
B.IL=new A.bl("remada-mesa",B.MI,"Remada na mesa (australiana)",B.iQ)
B.Mg=s(["De bru\xe7os, eleve bra\xe7o direito e perna esquerda juntos.","Alterne com o lado oposto, como se nadasse.","Movimento cont\xednuo e controlado, abd\xf4men firme."],t.s)
B.If=new A.bl("nadador",B.Mg,"Nadador",B.iQ)
B.Mf=s(["Sente na beirada de uma cadeira firme, m\xe3os ao lado do quadril.","Deslize o corpo \xe0 frente e des\xe7a dobrando os cotovelos para tr\xe1s.","Cotovelos apontando para tr\xe1s (n\xe3o para os lados).","Suba empurrando com os tr\xedceps. Pernas mais estendidas = mais dif\xedcil."],t.s)
B.II=new A.bl("mergulho-cadeira",B.Mf,"Mergulho na cadeira (tr\xedceps)",B.iR)
B.Nm=s(["Segure uma toalha com uma m\xe3o por baixo e pise/segure a outra ponta.","Puxe como uma rosca de b\xedceps, resistindo com a outra ponta.","Segure a contra\xe7\xe3o por 10\u201320 segundos e troque o bra\xe7o."],t.s)
B.Io=new A.bl("rosca-isometrica",B.Nm,"Rosca isom\xe9trica com toalha",B.iR)
B.OI=s(["Apoie as m\xe3os numa superf\xedcie elevada (mesa, sof\xe1, parede).","Corpo reto da cabe\xe7a aos calcanhares, abd\xf4men firme.","Des\xe7a o peito em dire\xe7\xe3o ao apoio e empurre de volta.","Quanto mais alto o apoio, mais f\xe1cil \u2014 comece confort\xe1vel."],t.s)
B.Iv=new A.bl("flexao-inclinada",B.OI,"Flex\xe3o inclinada",B.cs)
B.Mw=s(["Joelhos no ch\xe3o, tronco e quadril alinhados (sem empinar).","M\xe3os na largura dos ombros.","Des\xe7a o peito at\xe9 perto do ch\xe3o e suba controlando."],t.s)
B.Il=new A.bl("flexao-joelhos",B.Mw,"Flex\xe3o de joelhos",B.cs)
B.MV=s(["Junte as m\xe3os formando um losango (polegares e indicadores).","Cotovelos rentes ao corpo \u2014 foco no tr\xedceps.","Des\xe7a com controle e suba sem trancar os cotovelos."],t.s)
B.It=new A.bl("flexao-diamante",B.MV,"Flex\xe3o diamante (tr\xedceps)",B.iR)
B.MT=s(["P\xe9s apoiados numa eleva\xe7\xe3o (banco, degrau).","Corpo reto, abd\xf4men firme, olhar para o ch\xe3o.","Des\xe7a o peito e empurre \u2014 foco na parte alta do peitoral."],t.s)
B.Iz=new A.bl("flexao-declinada",B.MT,"Flex\xe3o declinada",B.cs)
B.Om=s(["M\xe3os bem afastadas; des\xe7a deslocando o peso para um lado.",'Um bra\xe7o dobra, o outro estica ("como um arqueiro").',"Alterne os lados a cada repeti\xe7\xe3o."],t.s)
B.IC=new A.bl("flexao-arqueiro",B.Om,"Flex\xe3o arqueiro",B.cs)
B.NC=s(["Des\xe7a controlado e suba com for\xe7a, tirando as m\xe3os do ch\xe3o.","Amorte\xe7a a queda dobrando os cotovelos.","S\xf3 avance para ela com a flex\xe3o tradicional bem s\xf3lida."],t.s)
B.IJ=new A.bl("flexao-explosiva",B.NC,"Flex\xe3o explosiva",B.cs)
B.N2=s(["M\xe3os na altura da cintura, dedos apontando para tr\xe1s/lados.","Incline o corpo \xe0 frente, ombros passando das m\xe3os.","Movimento curto e muito controlado."],t.s)
