B.ND=s(["Na prancha alta, traga os joelhos ao peito alternadamente.","Quadril baixo e est\xe1vel, sem empinar.","Controle o ritmo conforme seu preparo."],t.s)
B.Iy=new A.bl("escalador",B.ND,"Escalador",B.cW)
